use distributed_inference::mesh_residual_deblur::{
    mesh_residual_deblur_rgb_f32, MeshResidualDeblurCertificate, MeshResidualDeblurConfig,
};
use serde::Serialize;
use std::hint::black_box;
use std::path::PathBuf;
use std::time::Instant;

const CERTIFICATE_VERSION: &str = "gnosis.mesh-leech-shell-cache.v2";

#[derive(Clone, Debug)]
struct Config {
    width: u32,
    height: u32,
    stride: usize,
    repeats: usize,
    cache_entries: usize,
    output: Option<PathBuf>,
}

impl Default for Config {
    fn default() -> Self {
        Self {
            width: 128,
            height: 128,
            stride: 32,
            repeats: 3,
            cache_entries: 256,
            output: None,
        }
    }
}

fn parse_args() -> Config {
    let mut cfg = Config::default();
    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        let Some(value) = args.next() else {
            panic!("missing value for {arg}");
        };
        match arg.as_str() {
            "--width" => cfg.width = parse_u32(&arg, &value, 1),
            "--height" => cfg.height = parse_u32(&arg, &value, 1),
            "--stride" => cfg.stride = parse_usize(&arg, &value, 1),
            "--repeats" => cfg.repeats = parse_usize(&arg, &value, 1),
            "--cache-entries" => cfg.cache_entries = parse_usize(&arg, &value, 1),
            "--output" => cfg.output = Some(PathBuf::from(value)),
            _ => panic!("unknown argument: {arg}"),
        }
    }
    cfg
}

fn parse_u32(name: &str, value: &str, min: u32) -> u32 {
    value
        .parse::<u32>()
        .ok()
        .filter(|v| *v >= min)
        .unwrap_or_else(|| panic!("{name} must be an integer >= {min}"))
}

fn parse_usize(name: &str, value: &str, min: usize) -> usize {
    value
        .parse::<usize>()
        .ok()
        .filter(|v| *v >= min)
        .unwrap_or_else(|| panic!("{name} must be an integer >= {min}"))
}

fn synthetic_rgb(width: u32, height: u32) -> Vec<f32> {
    let w = width as usize;
    let h = height as usize;
    let mut rgb = vec![0.0_f32; w * h * 3];
    for y in 0..h {
        for x in 0..w {
            let base = (y * w + x) * 3;
            let fx = x as f32;
            let fy = y as f32;
            let edge = if x >= w / 2 { 0.82 } else { 0.18 };
            let ripple = 0.10 * (fx * 0.071).sin() + 0.07 * (fy * 0.053).cos();
            let stripe = if (x + 2 * y) % 17 < 8 { 0.05 } else { -0.03 };
            let v = (edge + ripple + stripe).clamp(0.0, 1.0);
            rgb[base] = v;
            rgb[base + 1] = (0.92 * v + 0.06 * (fx * 0.031).cos()).clamp(0.0, 1.0);
            rgb[base + 2] = (0.78 * v + 0.09 * (fy * 0.037).sin()).clamp(0.0, 1.0);
        }
    }
    rgb
}

fn median(mut values: Vec<f64>) -> f64 {
    values.sort_by(|a, b| a.total_cmp(b));
    let mid = values.len() / 2;
    if values.len().is_multiple_of(2) {
        0.5 * (values[mid - 1] + values[mid])
    } else {
        values[mid]
    }
}

fn hash_rgb(rgb: &[f32]) -> u64 {
    let mut hash = 0xcbf2_9ce4_8422_2325_u64;
    for value in rgb {
        for byte in value.to_bits().to_le_bytes() {
            hash ^= u64::from(byte);
            hash = hash.wrapping_mul(0x0000_0100_0000_01b3);
        }
    }
    hash
}

#[derive(Clone, Debug)]
struct RunSample {
    ms: f64,
    rgb_hash: u64,
    certificate: MeshResidualDeblurCertificate,
}

fn run_once(rgb: &[f32], width: u32, height: u32, cfg: &MeshResidualDeblurConfig) -> RunSample {
    let t0 = Instant::now();
    let result = mesh_residual_deblur_rgb_f32(rgb, width, height, cfg).expect("mesh deblur");
    let ms = t0.elapsed().as_secs_f64() * 1000.0;
    let rgb_hash = hash_rgb(&result.rgb);
    black_box(result.certificate.max_channel_delta);
    black_box(result.certificate.leech_visual_unique_keys);
    black_box(result.certificate.leech_visual_resident_cache_hits);
    RunSample {
        ms,
        rgb_hash,
        certificate: result.certificate,
    }
}

#[derive(Serialize)]
struct BenchPayload {
    #[serde(rename = "certificateVersion")]
    certificate_version: &'static str,
    tool: &'static str,
    scope: &'static str,
    config: BenchConfigPayload,
    modes: Vec<ModePayload>,
    invariants: InvariantsPayload,
    #[serde(rename = "cacheAdmission")]
    cache_admission: CacheAdmissionPayload,
    #[serde(rename = "proof_spine")]
    proof_spine: Vec<ProofSpineEntry>,
}

#[derive(Serialize)]
struct BenchConfigPayload {
    width: u32,
    height: u32,
    stride: usize,
    repeats: usize,
    cache_entries: usize,
}

#[derive(Serialize)]
struct ModePayload {
    name: &'static str,
    median_ms: f64,
    samples_ms: Vec<f64>,
    rgb_hash: String,
    certificate: ModeCertificatePayload,
}

#[derive(Serialize)]
struct ModeCertificatePayload {
    leech_visual_sieve: String,
    sampled_pixels: u32,
    shell_keys: u32,
    addressable_shell_keys: u32,
    unique_keys: u32,
    route_bucket_count: u32,
    route_hint_boost: f32,
    unique_route_buckets: u32,
    route_bucket_hint_entries: u32,
    route_bucket_hint_reuses: u64,
    route_bucket_hint_applies: u64,
    route_bucket_hint_mean_gate_delta: f32,
    route_bucket_hint_max_gate_delta: f32,
    route_bucket_mean_admission: f32,
    route_bucket_max_admission: f32,
    resident_cache_enabled: bool,
    resident_cache_entries: u32,
    resident_cache_hits: u64,
    resident_cache_payload_reuses: u64,
    resident_cache_bucket_reuses: u64,
    resident_cache_misses: u64,
    resident_cache_refusals: u64,
    resident_cache_stores: u64,
    max_channel_delta: f32,
}

#[derive(Serialize)]
struct InvariantsPayload {
    sieve_matches_off_rgb: bool,
    cache_matches_sieve_rgb: bool,
    cache_matches_off_rgb: bool,
}

#[derive(Serialize)]
struct CacheAdmissionPayload {
    candidate: bool,
    policy: &'static str,
    reason: &'static str,
}

#[derive(Serialize)]
struct ProofSpineEntry {
    key: &'static str,
    module: &'static str,
}

fn mode_payload(name: &'static str, samples: &[RunSample]) -> ModePayload {
    let last = samples.last().expect("mode has at least one sample");
    ModePayload {
        name,
        median_ms: median(samples.iter().map(|sample| sample.ms).collect()),
        samples_ms: samples.iter().map(|sample| sample.ms).collect(),
        rgb_hash: format!("{:016x}", last.rgb_hash),
        certificate: ModeCertificatePayload {
            leech_visual_sieve: last.certificate.leech_visual_sieve.clone(),
            sampled_pixels: last.certificate.leech_visual_sampled_pixels,
            shell_keys: last.certificate.leech_visual_shell_keys,
            addressable_shell_keys: last.certificate.leech_visual_addressable_shell_keys,
            unique_keys: last.certificate.leech_visual_unique_keys,
            route_bucket_count: last.certificate.leech_visual_route_bucket_count,
            route_hint_boost: last.certificate.leech_visual_route_hint_boost,
            unique_route_buckets: last.certificate.leech_visual_unique_route_buckets,
            route_bucket_hint_entries: last.certificate.leech_visual_route_bucket_hint_entries,
            route_bucket_hint_reuses: last.certificate.leech_visual_route_bucket_hint_reuses,
            route_bucket_hint_applies: last.certificate.leech_visual_route_bucket_hint_applies,
            route_bucket_hint_mean_gate_delta: last
                .certificate
                .leech_visual_route_bucket_hint_mean_gate_delta,
            route_bucket_hint_max_gate_delta: last
                .certificate
                .leech_visual_route_bucket_hint_max_gate_delta,
            route_bucket_mean_admission: last
                .certificate
                .leech_visual_route_bucket_mean_admission,
            route_bucket_max_admission: last
                .certificate
                .leech_visual_route_bucket_max_admission,
            resident_cache_enabled: last.certificate.leech_visual_resident_cache_enabled,
            resident_cache_entries: last.certificate.leech_visual_resident_cache_entries,
            resident_cache_hits: last.certificate.leech_visual_resident_cache_hits,
            resident_cache_payload_reuses: last
                .certificate
                .leech_visual_resident_cache_payload_reuses,
            resident_cache_bucket_reuses: last
                .certificate
                .leech_visual_resident_cache_bucket_reuses,
            resident_cache_misses: last.certificate.leech_visual_resident_cache_misses,
            resident_cache_refusals: last.certificate.leech_visual_resident_cache_refusals,
            resident_cache_stores: last.certificate.leech_visual_resident_cache_stores,
            max_channel_delta: last.certificate.max_channel_delta,
        },
    }
}

fn build_payload(
    cfg: &Config,
    off_samples: &[RunSample],
    sieve_samples: &[RunSample],
    cache_samples: &[RunSample],
) -> BenchPayload {
    let off_hash = off_samples.last().expect("off sample").rgb_hash;
    let sieve_hash = sieve_samples.last().expect("sieve sample").rgb_hash;
    let cache_last = cache_samples.last().expect("cache sample");
    let cache_hash = cache_last.rgb_hash;
    let cert = &cache_last.certificate;
    let candidate = cert.leech_visual_resident_cache_enabled
        && cert.leech_visual_addressable_shell_keys > 0
        && cert.leech_visual_resident_cache_stores > 0
        && cert.leech_visual_resident_cache_payload_reuses > 0
        && cert.leech_visual_resident_cache_bucket_reuses > 0
        && cert.leech_visual_route_bucket_hint_reuses > 0
        && cert.leech_visual_route_bucket_hint_applies > 0
        && cert.leech_visual_route_bucket_hint_max_gate_delta > 0.0
        && cache_hash != sieve_hash;

    BenchPayload {
        certificate_version: CERTIFICATE_VERSION,
        tool: "bench-mesh-leech-toggle",
        scope: "mesh residual deblur; Leech visual sieve resident shell-cache telemetry",
        config: BenchConfigPayload {
            width: cfg.width,
            height: cfg.height,
            stride: cfg.stride,
            repeats: cfg.repeats,
            cache_entries: cfg.cache_entries,
        },
        modes: vec![
            mode_payload("off", off_samples),
            mode_payload("sieve", sieve_samples),
            mode_payload("resident_cache", cache_samples),
        ],
        invariants: InvariantsPayload {
            sieve_matches_off_rgb: sieve_hash == off_hash,
            cache_matches_sieve_rgb: cache_hash == sieve_hash,
            cache_matches_off_rgb: cache_hash == off_hash,
        },
        cache_admission: CacheAdmissionPayload {
            candidate,
            policy: "resident cache enabled && addressable shells > 0 && stores > 0 && payload_reuses > 0 && bucket_reuses > 0 && hint_applies > 0 && hint gate delta > 0 && cache rgb diverges from sieve",
            reason: if candidate {
                "mesh pass applied repeated exact-address Leech route-bucket admission hints to the hotpath"
            } else {
                "mesh pass did not apply resident exact-address route-bucket admission hints"
            },
        },
        proof_spine: vec![
            ProofSpineEntry {
                key: "aizawa-leech-cache",
                module: "Gnosis.AizawaLeechCompletion",
            },
            ProofSpineEntry {
                key: "runtime-leech-shell-cache",
                module: "distributed_inference::leech_visual_sieve",
            },
        ],
    }
}

fn write_payload(path: &PathBuf, payload: &BenchPayload) {
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).expect("create output directory");
    }
    let json = serde_json::to_string_pretty(payload).expect("serialize benchmark payload");
    std::fs::write(path, format!("{json}\n")).expect("write benchmark payload");
}

fn main() {
    let cfg = parse_args();
    let rgb = synthetic_rgb(cfg.width, cfg.height);
    let off_cfg = MeshResidualDeblurConfig::default();
    let mut on_cfg = off_cfg.clone();
    on_cfg.enable_leech_visual_sieve = true;
    on_cfg.leech_visual_stride = cfg.stride;
    let mut cache_cfg = on_cfg.clone();
    cache_cfg.enable_leech_visual_shell_cache = true;
    cache_cfg.leech_visual_shell_cache_max_entries = cfg.cache_entries;

    let mut off_samples = Vec::with_capacity(cfg.repeats);
    let mut on_samples = Vec::with_capacity(cfg.repeats);
    let mut cache_samples = Vec::with_capacity(cfg.repeats);

    for _ in 0..cfg.repeats {
        off_samples.push(run_once(&rgb, cfg.width, cfg.height, &off_cfg));
        on_samples.push(run_once(&rgb, cfg.width, cfg.height, &on_cfg));
        cache_samples.push(run_once(&rgb, cfg.width, cfg.height, &cache_cfg));
    }

    let payload = build_payload(&cfg, &off_samples, &on_samples, &cache_samples);
    let off_median = payload.modes[0].median_ms;
    let on_median = payload.modes[1].median_ms;
    let cache_median = payload.modes[2].median_ms;
    let delta = on_median - off_median;
    let delta_pct = if off_median > 0.0 {
        100.0 * delta / off_median
    } else {
        0.0
    };
    let cache_delta = cache_median - on_median;
    let cache_delta_pct = if on_median > 0.0 {
        100.0 * cache_delta / on_median
    } else {
        0.0
    };
    let cache_cert = &payload.modes[2].certificate;

    println!("Mesh residual deblur Leech toggle bench");
    println!(
        "  image: {}x{}, stride={}, repeats={}, sampled={}",
        cfg.width, cfg.height, cfg.stride, cfg.repeats, cache_cert.sampled_pixels
    );
    println!(
        "  off median:   {:.3}ms samples={:?}",
        off_median, payload.modes[0].samples_ms
    );
    println!(
        "  sieve median: {:.3}ms samples={:?}",
        on_median, payload.modes[1].samples_ms
    );
    println!(
        "  cache median: {:.3}ms samples={:?}",
        cache_median, payload.modes[2].samples_ms
    );
    println!("  sieve delta:  {:+.3}ms ({:+.3}%)", delta, delta_pct);
    println!(
        "  cache delta:  {:+.3}ms ({:+.3}%)",
        cache_delta, cache_delta_pct
    );
    println!(
        "  cache: addressable={} route_buckets={}/{} hints={} hint_reuses={} hint_applies={} hint_delta_mean={:.3} hint_adm_mean={:.3} entries={} hits={} payload_reuses={} bucket_reuses={} misses={} refusals={} stores={} candidate={}",
        cache_cert.addressable_shell_keys,
        cache_cert.unique_route_buckets,
        cache_cert.route_bucket_count,
        cache_cert.route_bucket_hint_entries,
        cache_cert.route_bucket_hint_reuses,
        cache_cert.route_bucket_hint_applies,
        cache_cert.route_bucket_hint_mean_gate_delta,
        cache_cert.route_bucket_mean_admission,
        cache_cert.resident_cache_entries,
        cache_cert.resident_cache_hits,
        cache_cert.resident_cache_payload_reuses,
        cache_cert.resident_cache_bucket_reuses,
        cache_cert.resident_cache_misses,
        cache_cert.resident_cache_refusals,
        cache_cert.resident_cache_stores,
        payload.cache_admission.candidate
    );
    println!(
        "  invariants: sieve==off {} cache==sieve {} cache==off {}",
        payload.invariants.sieve_matches_off_rgb,
        payload.invariants.cache_matches_sieve_rgb,
        payload.invariants.cache_matches_off_rgb
    );

    if let Some(output) = &cfg.output {
        write_payload(output, &payload);
        println!("  wrote: {}", output.display());
    }
}
